# --- Helpers ---

def http_json(url):
    req = urllib.request.Request(url, headers={"User-Agent": USER_AGENT})
    with urllib.request.urlopen(req, timeout=20) as r:
        return json.loads(r.read().decode("utf-8"))


def wiki_extract_ru(title):
    """Возвращает (extract, description) или (None, None)."""
    try:
        url = f"https://ru.wikipedia.org/api/rest_v1/page/summary/{urllib.parse.quote(title)}"
        d = http_json(url)
        return d.get("extract") or "", d.get("description") or ""
    except (HTTPError, URLError) as e:
        return "", ""


def build_default_historical(name, wiki_music, wiki_main):
    """Вытягиваем текст из ru.wikipedia (если есть статья про музыку — лучше).
    Возвращаем структуру с 15 плоскими ключами, как ожидает фронт."""
    summary = ""
    if wiki_music:
        summary, _ = wiki_extract_ru(wiki_music)
        time.sleep(0.2)
    if not summary and wiki_main:
        summary, _ = wiki_extract_ru(wiki_main)
        time.sleep(0.2)
    fallback_msg = (
        f"Подробная справка по региону «{name}» сейчас собирается редакцией "
        "Сонатум. Если вы можете поделиться материалами — напишите info@sonatum-music.ru."
    )
    if not summary:
        summary = fallback_msg
    return {
        "summary": summary[:600],
        # Кладём wiki-текст в geography (первая секция), остальные пустые.
        "geography": summary,
        "roots": "",
        "school": "",
        "genres": "",
        "instruments": "",
        "spiritualCenters": "",
        "composers": "",
        "performers": "",
        "expeditions": "",
        "preservation": "",
        "modern": "",
        "unique": "",
        "influence": "",
        "heritage": "",
        "projects": "",
        "shortDescription": summary[:300],
        "source": "ru.wikipedia.org" if wiki_music or wiki_main else "редакция Сонатум",
    }


def cuid_like():
    import uuid
    return f"reg_{uuid.uuid4().hex[:24]}"


def upsert_region(cur, slug, name, type_, lat, lng, color, hist):
    cur.execute("SELECT id FROM regions WHERE slug = %s", (slug,))
    row = cur.fetchone()
    coords = json.dumps([lat, lng])
    hist_json = json.dumps(hist, ensure_ascii=False)
    if row:
        cur.execute(
            'UPDATE regions SET name=%s, type=%s, "centerCoordinates"=%s::jsonb, '
            '"identityColor"=%s, "historicalData"=%s::jsonb WHERE id=%s',
            (name, type_, coords, color, hist_json, row[0]),
        )
        return row[0], "updated"
    rid = cuid_like()
    cur.execute(
        'INSERT INTO regions (id, name, slug, type, "centerCoordinates", "identityColor", "historicalData") '
        'VALUES (%s, %s, %s, %s, %s::jsonb, %s, %s::jsonb)',
        (rid, name, slug, type_, coords, color, hist_json),
    )
    return rid, "created"


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--force", action="store_true", help="Перезаписать всё, включая существующие историч. справки")
    parser.add_argument("--only", help="Запустить только для одного slug (для отладки)")
    args = parser.parse_args()

    conn = psycopg2.connect(**DB)
    conn.autocommit = False
    cur = conn.cursor()

    total = created = updated = skipped = 0
    for slug, name, type_, lat, lng, color, wiki_music, wiki_main in REGIONS:
        if args.only and slug != args.only:
            continue
        total += 1
        # Не трогаем уже заполненные справки если без --force
        if not args.force:
            cur.execute('SELECT "historicalData" FROM regions WHERE slug=%s', (slug,))
            existing = cur.fetchone()
            if existing and existing[0]:
                hd = existing[0]
                if isinstance(hd, dict) and hd.get("source") == "редакция Сонатум" and hd.get("sections"):
                    print(f"  = skip (already curated): {name}")
                    skipped += 1
                    continue

        if slug in HISTORICAL_TEMPLATES:
            tpl = HISTORICAL_TEMPLATES[slug]
            hist = {**tpl, "shortDescription": tpl["summary"][:300]}
            print(f"  + curated: {name}")
        else:
            hist = build_default_historical(name, wiki_music, wiki_main)
            print(f"  + wiki: {name}")

        _id, action = upsert_region(cur, slug, name, type_, lat, lng, color, hist)
        if action == "created":
            created += 1
        else:
            updated += 1
        conn.commit()

    cur.close(); conn.close()
    print(f"\nDone: {total} regions ({created} created, {updated} updated, {skipped} skipped)")


if __name__ == "__main__":
    main()
